-- Formulas
insert into formulas (output_param_id, expression, expression_human, dependencies, description) values
  ((select id from parameters where code = 'electricity_mwh'),
   'electricity_total/1000',
   '=Input!N8/1000',
   ARRAY['electricity_total']::text[],
   'Metered kWh ÷ 1,000. 100% renewable (Vattenfall GvO EU Wind).'),
  ((select id from parameters where code = 'biogas_self_mwh'),
   'biogas_produced*biogas_ch4_fraction/100*biogas_ch4_hhv/3.6/1000',
   '=Input!N10*Input!N11/100*Input!N77/3.6/1000',
   ARRAY['biogas_produced', 'biogas_ch4_fraction', 'biogas_ch4_hhv']::text[],
   'Biogas m³ × CH₄% × 35.88 MJ/m³ ÷ 3.6 ÷ 1,000. Classified renewable.'),
  ((select id from parameters where code = 'natural_gas_mwh'),
   'natural_gas*ng_density*ng_ncv_tj_gg/3.6/1000',
   '=Input!N9*Input!N73*Input!N74/3.6/1000',
   ARRAY['natural_gas', 'ng_density', 'ng_ncv_tj_gg']::text[],
   '227,997 m³ × 0.7 kg/m³ × 48 TJ/Gg, converted to MWh (VSME Fuel-Converter route).'),
  ((select id from parameters where code = 'total_energy_mwh'),
   'electricity_mwh+biogas_self_mwh+natural_gas_mwh',
   '=D6+D7+D8',
   ARRAY['electricity_mwh', 'biogas_self_mwh', 'natural_gas_mwh']::text[],
   'Electricity + self-generated biogas + natural gas.'),
  ((select id from parameters where code = 'ng_combustion_gj'),
   'natural_gas*ng_net_cv_mj_m3/1000',
   '=Input!N9*Input!N76/1000',
   ARRAY['natural_gas', 'ng_net_cv_mj_m3']::text[],
   '227,997 m³ × 31.65 MJ/m³ (Dutch G-gas net CV) ÷ 1,000. NB: differs from energy-disclosure basis above.'),
  ((select id from parameters where code = 'scope1_ng_co2'),
   'ng_combustion_gj*ef_ng_co2_kg_gj/1000',
   '=D12*Input!N78/1000',
   ARRAY['ng_combustion_gj', 'ef_ng_co2_kg_gj']::text[],
